export const getAllLessons = () =>
  lessonsCategories.flatMap(cat =>
    cat.lessons.map(l => ({ ...l, categoryTitle: cat.title, categoryIcon: cat.icon }))
  );

export const getLessonById = (id) => getAllLessons().find(l => l.id === id);